function executeSkill(context) {
    // context.player 由 triggers.ts 注入，是拥有 rule-blizzard-active 的玩家对象
    var sourcePlayer = context.player;
    if (!sourcePlayer) {
      // 兜底：通过 playerId 查找
      if (context.playerId) {
        sourcePlayer = context.battle.players.find(function(p) { return p.playerId === context.playerId; });
      }
    }
    if (!sourcePlayer) return { message: '找不到暴风雪施法者', success: false };
    var sourcePlayerId = sourcePlayer.playerId;
    if (context.battle.turn.currentPlayerId === sourcePlayerId) return { message: '暴风雪只在对方回合结束时触发', success: false };
    var blizzardStatus = sourcePlayer.statusTags && sourcePlayer.statusTags.find(function(t) { return t.type === 'blizzard'; });
    if (!blizzardStatus) return { message: '没有暴风雪状态', success: false };
    var centerX = blizzardStatus.centerX;
    var centerY = blizzardStatus.centerY;
    var damageValue = blizzardStatus.damage;
    var bSourceId = blizzardStatus.id;
    // 清理三件套
    removePlayerStatusEffectById(sourcePlayerId, blizzardStatus.id);
    removePlayerRuleById(sourcePlayerId, 'rule-blizzard-active');
    removePlayerSkillById(sourcePlayerId, 'blizzard-damage');
    if (context.battle.extensions && context.battle.extensions.tileEffects) {
      context.battle.extensions.tileEffects = context.battle.extensions.tileEffects.filter(function(te) { return te.sourceId !== bSourceId; });
    }
    var radius = 3;
    var enemiesInArea = context.battle.pieces.filter(function(piece) {
      if (piece.ownerPlayerId === sourcePlayerId) return false;
      if (piece.currentHp <= 0) return false;
      return Math.abs(piece.x - centerX) <= radius && Math.abs(piece.y - centerY) <= radius;
    });
    var attackerPiece = context.battle.pieces.find(function(p) { return p.ownerPlayerId === sourcePlayerId && p.currentHp > 0; });
    if (!attackerPiece) return { message: '施法者已无存活棋子，暴风雪自动消散', success: true };
    var dmgResult = dealDamage(attackerPiece, enemiesInArea, damageValue, 'magical', context.battle, 'blizzard');
    var totalDamage = dmgResult.totalDamage || 0;
    enemiesInArea.forEach(function(enemy, i) {
      var r = dmgResult.results && dmgResult.results[i];
      if (r && r.success) {
        var statusId = 'freeze-' + Date.now() + '-' + enemy.instanceId;
        addStatusEffectById(enemy.instanceId, { id: statusId, type: 'freeze', currentDuration: 2, intensity: 1 });
        addRuleById(enemy.instanceId, 'rule-freeze-prevent-move');
        addRuleById(enemy.instanceId, 'rule-freeze-prevent-skill');
        addSkillById(enemy.instanceId, 'freeze-prevent');
        enemy.showFreezeEffect = true;
      }
    });
    if (!context.battle.effects) { context.battle.effects = []; }
    for (var bx = centerX - radius; bx <= centerX + radius; bx++) {
      for (var by = centerY - radius; by <= centerY + radius; by++) {
        context.battle.effects.push({ type: 'blizzard', position: { x: bx, y: by }, duration: 1, zIndex: 999, showOnUI: true });
      }
    }
    var hitEnemies = enemiesInArea.filter(function(e, i) { return dmgResult.results && dmgResult.results[i] && dmgResult.results[i].success; });
    var message = attackerPiece.name + '的暴风雪效果（中心坐标：(' + centerX + ',' + centerY + ')）';
    if (hitEnemies.length > 0) {
      message += '对' + hitEnemies.map(function(e) { return e.name; }).join('、') + '造成了' + totalDamage + '点伤害并使其冰冻';
    } else {
      message += '没有对任何敌人造成伤害';
    }
    return { message: message, success: true, showUIEffects: true };
  }
